diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index c8407e8ba5ab..3af4242034f2 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3344,6 +3344,10 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
       unsigned Code = IsAnd ? getICmpCode(PredL) & getICmpCode(PredR)
                             : getICmpCode(PredL) | getICmpCode(PredR);
       bool IsSigned = LHS->isSigned() || RHS->isSigned();
+      // Poison-safety: Avoid collapsing to a single icmp if either operand has
+      // the samesign flag, because that icmp may be poison.
+      if (LHS->hasSameSign() || RHS->hasSameSign())
+        return nullptr;
       return getNewICmpValue(Code, IsSigned, LHS0, LHS1, Builder);
     }
   }
@@ -4176,6 +4180,10 @@ Value *InstCombinerImpl::foldXorOfICmps(ICmpInst *LHS, ICmpInst *RHS,
       // (icmp1 A, B) ^ (icmp2 A, B) --> (icmp3 A, B)
       unsigned Code = getICmpCode(PredL) ^ getICmpCode(PredR);
       bool IsSigned = LHS->isSigned() || RHS->isSigned();
+      // Poison-safety: Avoid collapsing to a single icmp if either operand has
+      // the samesign flag, because that icmp may be poison.
+      if (LHS->hasSameSign() || RHS->hasSameSign())
+        return nullptr;
       return getNewICmpValue(Code, IsSigned, LHS0, LHS1, Builder);
     }
   }
@@ -5024,4 +5032,4 @@ Instruction *InstCombinerImpl::visitXor(BinaryOperator &I) {
     return Res;

   return nullptr;
-}
+}
