index 7129499e0f8f..572e66f6f2d0 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7388,6 +7388,16 @@ Instruction *InstCombinerImpl::foldICmpCommutative(ICmpInst::Predicate Pred,
 }

 Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
+  // Canonicalize: drop samesign flag when one operand is a constant.
+  // Comparing to a known constant does not require sign-safety and avoids poison differences.
+  if (I.hasSameSign()) {
+    const APInt *C;
+    if (match(I.getOperand(0), m_APInt(C)) || match(I.getOperand(1), m_APInt(C))) {
+      I.setSameSign(false);
+      Worklist.add(&I);
+    }
+  }
+
   bool Changed = false;
   const SimplifyQuery Q = SQ.getWithInstruction(&I);
   Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1);
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 8be2eeed84ad..95fb87694997 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -1448,6 +1448,14 @@ Instruction *InstCombinerImpl::foldSelectEqualityTest(SelectInst &Sel) {
              m_c_SpecificICmp(ICmpInst::ICMP_EQ, m_Specific(X), m_Specific(Y))))
     return nullptr;

+  // Poison-safety: If the resulting compare has the samesign flag, drop it to avoid
+  // introducing a potentially-poisonous icmp.
+  if (auto *XIcmp = dyn_cast<ICmpInst>(XeqY)) {
+    if (XIcmp->hasSameSign()) {
+      XIcmp->setSameSign(false);
+      Worklist.add(XIcmp);
+    }
+  }
   return replaceInstUsesWith(Sel, XeqY);
 }

@@ -4203,8 +4211,16 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
   }

   // select Cond, !X, X -> xor Cond, X
-  if (CondVal->getType() == SI.getType() && isKnownInversion(FalseVal, TrueVal))
-    return BinaryOperator::CreateXor(CondVal, FalseVal);
+  // Guard to avoid changing poison semantics: require RHS (X) to be safe-to-speculatively-execute.
+  if (CondVal->getType() == SI.getType() && isKnownInversion(FalseVal, TrueVal)) {
+    if (isa<Constant>(FalseVal))
+      return BinaryOperator::CreateXor(CondVal, FalseVal);
+    if (auto *XI = dyn_cast<Instruction>(FalseVal)) {
+      SimplifyQuery Q = SQ.getWithInstruction(&SI);
+      if (isSafeToSpeculativelyExecute(XI, &SI, Q.AC, Q.DT, &TLI, /*InSpeculation=*/false))
+        return BinaryOperator::CreateXor(CondVal, FalseVal);
+    }
+  }

   // For vectors, this transform is only safe if the simplification does not
   // look through any lane-crossing operations. For now, limit to scalars only.

